export class EntryDetector {
  constructor(private readonly config: AnalysisConfig) {}

  /**
   * Detect Fair Value Gaps.
   * Bullish FVG: candle[i-1].high < candle[i+1].low (gap between first and third candle)
   * Bearish FVG: candle[i-1].low > candle[i+1].high
   * The middle candle (i) is the displacement candle.
   * Filter: FVG size must be >= fvgMinSizeMultiplier * ATR
   */
  detectFVGs(candles: readonly Candle[]): readonly FairValueGap[]

  /**
   * Detect Order Blocks.
   * Bullish OB: the last bearish (down-close) candle before a bullish BOS/displacement up.
   * Bearish OB: the last bullish (up-close) candle before a bearish BOS/displacement down.
   * The OB range is the full body of that candle (open to close).
   */
  detectOrderBlocks(
    candles: readonly Candle[],
    structureBreaks: readonly StructureBreak[]
  ): readonly OrderBlock[]

  /**
   * Track FVG fill status.
   * A bullish FVG is filled when price trades down into it (candle low enters FVG range).
   * Calculate fill percentage: how much of the FVG has been filled.
   */
  updateFVGFillStatus(
    fvgs: readonly FairValueGap[],
    candles: readonly Candle[],
    fromIndex: number
  ): readonly FairValueGap[]

  /**
   * Track Order Block mitigation.
   * Bullish OB mitigated: price trades down through the OB body midpoint.
   * Bearish OB mitigated: price trades up through the OB body midpoint.
   */
  updateOBMitigationStatus(
    obs: readonly OrderBlock[],
    candles: readonly Candle[],
    fromIndex: number
  ): readonly OrderBlock[]

  /**
   * Check for FVG + OB overlap (high confluence zone).
   * Returns EntryZone with overlap flag set.
   */
  findEntryZones(
    fvgs: readonly FairValueGap[],
    obs: readonly OrderBlock[],
    dealingRange: DealingRange | null,
    direction: TrendDirection
  ): readonly EntryZone[]
}
```

**FVG detection algorithm:**
1. Iterate from index 1 to length-2 (need 3 consecutive candles)
2. Bullish: check `candles[i-1].high < candles[i+1].low` -- the gap is between `candles[i-1].high` (low boundary) and `candles[i+1].low` (high boundary)
3. Bearish: check `candles[i-1].low > candles[i+1].high` -- the gap is between `candles[i+1].high` (low boundary) and `candles[i-1].low` (high boundary)
4. Calculate ATR and filter out FVGs smaller than `config.fvgMinSizeMultiplier * ATR`
5. Return with `filled: false, fillPercentage: 0` initially

**Order Block detection algorithm:**
1. For each structure break, look backward from the break candle
2. For a bullish break, find the last candle where `close < open` (bearish candle) before the break
3. For a bearish break, find the last candle where `close > open` (bullish candle) before the break
4. The OB boundaries are `min(open, close)` to `max(open, close)` of that candle
5. Body midpoint = midpoint of open and close

