  // Step 1: Validate
  validateCandles(candles);
  const config = validateConfig(this.analysisConfig ?? {});

  // Step 2: Session check
  const lastTimestamp = candles[candles.length - 1]!.timestamp;
  this.sessionManager.checkSessionDate(lastTimestamp);
  const sessionCheck = this.sessionManager.canTrade();
  if (!sessionCheck.allowed) {
    return this.buildNoTradeResult(lastTimestamp, sessionCheck.reason);
  }

  // Step 3: Kill zone + macro
  const killZone = this.killZoneManager.identifyKillZone(lastTimestamp);
  const macroWindow = this.killZoneManager.identifyMacroWindow(lastTimestamp);
  const tradingAllowed = this.killZoneManager.isTradingAllowed(lastTimestamp);
  if (!tradingAllowed.allowed) {
    return this.buildNoTradeResult(lastTimestamp, tradingAllowed.reason);
  }

  // Step 4: Swing points
  const swings = this.marketStructure.detectSwingPoints(candles);

  // Step 5: Trend + structure breaks
  const trend = this.marketStructure.determineTrend(swings);
  const structureBreaks = this.marketStructure.detectStructureBreaks(candles, swings);

  // Step 6: Dealing range
  const dealingRange = this.marketStructure.calculateDealingRange(swings);

  // Step 7: Liquidity levels
  const liquidityLevels = this.liquidityAnalyzer.mapLiquidityLevels(candles, swings);

  // Step 8: Sweeps
  const sweeps = this.liquidityAnalyzer.detectSweeps(candles, liquidityLevels);

  // Step 9: Entry zones (FVG + OB)
  const fvgs = this.entryDetector.detectFVGs(candles);
  const obs = this.entryDetector.detectOrderBlocks(candles, structureBreaks);
  const entryZones = this.entryDetector.findEntryZones(fvgs, obs, dealingRange, trend);
  const bestEntryZone = entryZones[0] ?? null; // highest confluence first

  // Step 10: AMD
  const asianRange = getAsianSessionRange(candles);
  const amdPattern = this.amdDetector.detectAMD(candles, sweeps, asianRange);

  // Step 11: Score
  const direction = trend; // trade direction follows structure
  const score = this.setupScorer.score({
    trend, structureBreaks, dealingRange, sweeps,
    entryZone: bestEntryZone, amdPattern, killZone, macroWindow,
    htfContext: htfContext ?? null, direction,
  });

  // Step 12: Risk calculation (only if score passes)
  let entry: EntryParams | undefined;
  if (!score.disqualified && bestEntryZone && score.grade !== 'F') {
    const entryPrice = /* derive from bestEntryZone midpoint or FVG boundary */;
    entry = this.riskCalculator.calculateEntry({
      direction, entryPrice, entryZone: bestEntryZone,
      instrumentConfig: this.instrumentConfig,
      riskParams: /* from config */,
      opposingLiquidity: liquidityLevels.filter(l => /* opposing direction */),
    }) ?? undefined;
  }

  // Step 13: Build result
  const tradeable = !score.disqualified && score.grade !== 'F' && score.grade !== 'D' && entry != null;

  return {
    timestamp: lastTimestamp,
    instrument: this.instrumentConfig.symbol,
    direction,
    score,
    entry,
    killZone,
    macroWindow,
    amdPattern,
    structure: { trend, lastBreak: structureBreaks[structureBreaks.length - 1], dealingRange },
    liquiditySweeps: sweeps,
    entryZone: bestEntryZone ?? undefined,
    htfContext,
    tradeable,
    reason: tradeable ? `${score.grade} setup in ${killZone?.name ?? 'unknown'} kill zone` : score.disqualificationReason ?? 'Score too low',
